package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.PlanningsurenCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.tools.Opdracht;
import com.google.common.collect.ImmutableSet;
import lombok.NoArgsConstructor;
import org.joda.time.LocalDate;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.function.Function;

@NoArgsConstructor
public class RkmCoreHrConfiguratieManagerImpl implements RkmCoreHrConfiguratieManager {

    private Set<RkmCoreHrConfiguratie> rkmCoreHrConfiguratieList = ImmutableSet.of();
    private Set<PlanningsurenCoreHrConfiguratie> planningsurenCoreHrConfiguratieList = ImmutableSet.of();

    private final Map<Integer, RkmCoreHrConfiguratie> rkmConfigMap = new HashMap<>();
    private final Map<Integer, PlanningsurenCoreHrConfiguratie> planningsurenConfigMap = new HashMap<>();

    public RkmCoreHrConfiguratieManagerImpl(List<RkmCoreHrConfiguratie> rkmCoreHrConfiguratieList) {
        this(rkmCoreHrConfiguratieList, new ArrayList<>());
    }

    public RkmCoreHrConfiguratieManagerImpl(
            List<RkmCoreHrConfiguratie> rkmCoreHrConfiguraties, List<PlanningsurenCoreHrConfiguratie> planningsurenCoreHrConfiguraties) {
        List<RkmCoreHrConfiguratie> rkmList = rkmCoreHrConfiguraties == null ? new ArrayList<>() : rkmCoreHrConfiguraties;
        List<PlanningsurenCoreHrConfiguratie> planningsurenist = planningsurenCoreHrConfiguraties == null ? new ArrayList<>() : planningsurenCoreHrConfiguraties;
        rkmCoreHrConfiguratieList = ImmutableSet.copyOf(rkmList);
        planningsurenCoreHrConfiguratieList = ImmutableSet.copyOf(planningsurenist);
    }

    @Override
    public RkmCoreHrConfiguratie getRkmCoreHrConfiguratie(Opdracht opdracht, RekenTijd rekenTijd) {
        if (rkmCoreHrConfiguratieList == null || rkmCoreHrConfiguratieList.isEmpty()) {
            return null;
        }
        return rkmConfigMap.computeIfAbsent(opdracht.getWerkgever().getId(),
                werkgeverId -> rkmCoreHrConfiguratieList.stream()
                        .filter(rkmCoreHrConfiguratie -> rkmCoreHrConfiguratie.getWerkgeverId().equals(werkgeverId))
                        .filter(rkmCoreHrConfiguratie -> filterOpBeginDatumRekentijd(RkmCoreHrConfiguratie::getActualFrom,
                                RkmCoreHrConfiguratie::getActualTo, rkmCoreHrConfiguratie, rekenTijd))
                        .findFirst()
                        .orElse(null));
    }

    @Override
    public PlanningsurenCoreHrConfiguratie getPlanningsurenCoreHrConfiguratie(Opdracht opdracht, RekenTijd rekenTijd) {
        if (planningsurenCoreHrConfiguratieList == null || planningsurenCoreHrConfiguratieList.isEmpty()) {
            return null;
        }
        return planningsurenConfigMap.computeIfAbsent(opdracht.getWerkgever().getId(),
                werkgeverId -> planningsurenCoreHrConfiguratieList.stream()
                        .filter(rkmCoreHrConfiguratie -> rkmCoreHrConfiguratie.getWerkgeverId().equals(werkgeverId))
                        .filter(rkmCoreHrConfiguratie -> filterOpBeginDatumRekentijd(PlanningsurenCoreHrConfiguratie::getActualFrom,
                                PlanningsurenCoreHrConfiguratie::getActualTo, rkmCoreHrConfiguratie, rekenTijd))
                        .findFirst()
                        .orElse(null));
    }


    private <T> boolean filterOpBeginDatumRekentijd(Function<T, LocalDate> fromGetter, Function<T, LocalDate> toGetter, T config, RekenTijd rekenTijd) {
        LocalDate actualTo = toGetter.apply(config);
        LocalDate actualFrom = fromGetter.apply(config);
        if (actualTo == null || actualFrom == null) {
            return false;
        }
        return (actualFrom.isBefore(rekenTijd.beginDatum) || actualFrom.equals(rekenTijd.beginDatum)) &&
                (actualTo.isAfter(rekenTijd.beginDatum) || actualTo.equals(rekenTijd.beginDatum));
    }
}
